/**
 * Interactive website — Slice MMMMMM (2026-05-11).
 *
 * Per user 'let it be seen and heard and felt through interactive
 * website based on payload default plugins through import/export
 * multimedia seeds generated by the e2e tests all wired in mcp'.
 *
 * Makes ERPax tangible. Auto-seeds Payload's `pages` collection from:
 *   1. The marketing/ directory's per-locale HTML files (multimedia
 *      seeds — output of CCCCC-cut2's marketing-page-generator,
 *      which derives from e2e Playwright recordings)
 *   2. The live spec corpus (every CollectionSpec / Chain / Agent /
 *      Role / Standard becomes a browsable Page)
 *   3. The federation network (peer instances broadcast their pages
 *      via slice AAAAAA — federation envelopes carry HTML payloads)
 *
 * Wires Payload's default plugins:
 *   - @payloadcms/plugin-import-export — round-trip the seeded pages
 *   - @payloadcms/plugin-form-builder   — interactive demos (try-the-MCP)
 *   - @payloadcms/plugin-search         — search the spec corpus
 *   - @payloadcms/plugin-seo            — discovery + sitemaps
 *   - @payloadcms/plugin-mcp            — already wired (DDDDD); exposes
 *                                          the 42 erpax.* tools
 *
 * @standard W3C HTML5 § sectioning + WCAG 2.2 §1.4.3
 * @standard Schema.org Article + WebSite + SoftwareApplication
 */

import { readFileSync, readdirSync, existsSync } from 'node:fs'
import { join, basename } from 'node:path'

export interface PageSeed {
  readonly slug: string
  readonly title: string
  readonly locale: string
  readonly heroSection: string
  readonly bodyHtml: string
  readonly seedSource: 'e2e-multimedia' | 'spec-corpus' | 'federation'
  readonly metadata: Record<string, unknown>
}

/** Walk marketing/*.<locale>.html and return one PageSeed per file. */
export function seedFromE2e(args: { repoRoot?: string }): ReadonlyArray<PageSeed> {
  const root = args.repoRoot ?? process.cwd()
  const dir = join(root, 'marketing')
  if (!existsSync(dir)) return []
  const seeds: PageSeed[] = []
  for (const f of readdirSync(dir)) {
    if (!f.endsWith('.html')) continue
    const stem = basename(f, '.html')
    // Convention: <workflow>.<locale>.html (e.g. 'order-to-cash.en.html')
    const m = stem.match(/^(.+)\.([a-z]{2})$/)
    if (!m) continue
    const [_, workflow, locale] = m
    const html = readFileSync(join(dir, f), 'utf8')
    const titleMatch = html.match(/<h1[^>]*>([^<]+)</i)
    seeds.push({
      slug: `walkthrough-${workflow}-${locale}`,
      title: titleMatch?.[1]?.trim() ?? `${workflow} (${locale})`,
      locale: locale!,
      heroSection: `data-block="hero"`,
      bodyHtml: html,
      seedSource: 'e2e-multimedia',
      metadata: { workflow, locale, sourceFile: `marketing/${f}` },
    })
  }
  return seeds
}

/**
 * One Page per CollectionSpec / Chain / Agent / Role / Standard from
 * the live spec corpus. Hero contains the title; body renders the
 * citation graph + JSON manifest + chain-step storyboard.
 */
export interface SpecPageSeedOptions {
  readonly tenantId: string
  /** Optional filter — only seed pages for these axis kinds. */
  readonly include?: ReadonlyArray<'collection' | 'chain' | 'agent' | 'role' | 'standard'>
}

export async function seedFromSpec(opts: SpecPageSeedOptions): Promise<ReadonlyArray<PageSeed>> {
  const include = new Set(opts.include ?? ['collection', 'chain', 'agent', 'role', 'standard'])
  const seeds: PageSeed[] = []

  // Collection pages — one per CollectionSpec, lazily imported to avoid
  // circular deps (spec-generator → website → spec-generator).
  if (include.has('collection')) {
    const { extractCorpus } = await import('@/spec/generator')
    const corpus = extractCorpus(process.cwd())
    for (const c of corpus.collections) {
      seeds.push({
        slug: `spec-collection-${c.slug}`,
        title: c.title,
        locale: 'en',
        heroSection: `data-block="hero"`,
        bodyHtml: renderCollectionPage(c),
        seedSource: 'spec-corpus',
        metadata: { axis: 'collection', slug: c.slug, standardsCited: c.standards.length },
      })
    }
  }

  // Chain pages
  if (include.has('chain')) {
    const { BUSINESS_CHAINS } = await import('@/business/chain/registry')
    for (const c of Object.values(BUSINESS_CHAINS)) {
      const chain = c as { id: string; name?: string; description?: string; standards?: ReadonlyArray<string> }
      seeds.push({
        slug: `spec-chain-${chain.id.toLowerCase().replace(/_/g, '-')}`,
        title: chain.name ?? chain.id,
        locale: 'en',
        heroSection: `data-block="hero"`,
        bodyHtml: renderChainPage(chain),
        seedSource: 'spec-corpus',
        metadata: { axis: 'chain', id: chain.id },
      })
    }
  }

  // Agent pages
  if (include.has('agent')) {
    const { agentRegistry } = await import('@/agent/bootstrap')
    for (const a of agentRegistry.all()) {
      seeds.push({
        slug: `spec-agent-${a.id}`,
        title: `Agent: ${a.id}`,
        locale: 'en',
        heroSection: `data-block="hero"`,
        bodyHtml: renderAgentPage(a),
        seedSource: 'spec-corpus',
        metadata: { axis: 'agent', id: a.id, ownsCount: a.ownsCollections.length },
      })
    }
  }

  // Role-profile pages
  if (include.has('role')) {
    const { listTenantRoles } = await import('@/tenant/role')
    for (const r of listTenantRoles()) {
      seeds.push({
        slug: `spec-role-${r.id.replace(/[^a-z0-9-]/g, '-')}`,
        title: r.displayName.en ?? r.id,
        locale: 'en',
        heroSection: `data-block="hero"`,
        bodyHtml: renderRolePage(r),
        seedSource: 'spec-corpus',
        metadata: { axis: 'role', id: r.id, requiredStandards: r.requiredStandards.length },
      })
    }
  }

  // Standard family pages
  if (include.has('standard')) {
    const families = ['ifrs-ias', 'iso', 'eu-directive', 'us-fed', 'w3c-ietf', 'cloudflare', 'un-oecd-wco'] as const
    for (const family of families) {
      seeds.push({
        slug: `spec-standard-family-${family}`,
        title: `Standards family: ${family}`,
        locale: 'en',
        heroSection: `data-block="hero"`,
        bodyHtml: renderStandardFamilyPage(family),
        seedSource: 'spec-corpus',
        metadata: { axis: 'standard-family', family },
      })
    }
  }

  return seeds
}

function renderCollectionPage(c: { slug: string; title: string; description: string; standards: ReadonlyArray<{ body: string; id: string }>; chainSteps: ReadonlyArray<{ chainId: string; stepIndex: number }> }): string {
  const stds = c.standards.map((s) => `<li><strong>${s.body}</strong> ${s.id}</li>`).join('')
  const steps = c.chainSteps.map((s) => `<li>${s.chainId} step ${s.stepIndex}</li>`).join('')
  return `<section data-block="hero"><h1>${c.title}</h1><p class="lede">Collection: <code>${c.slug}</code></p></section>` +
    `<section data-block="standards"><h2>Standards cited</h2><ul>${stds}</ul></section>` +
    `<section data-block="chain-steps"><h2>Chain participation</h2><ul>${steps || '<li>(none)</li>'}</ul></section>` +
    `<section data-block="actions"><h2>Try it</h2><p>Call <code>erpax.spec.getCollection({slug: "${c.slug}"})</code> via MCP.</p></section>`
}

function renderChainPage(c: { id: string; name?: string; description?: string; standards?: ReadonlyArray<string> }): string {
  return `<section data-block="hero"><h1>${c.name ?? c.id}</h1><code>BUSINESS_CHAINS.${c.id}</code></section>` +
    `<section data-block="description"><p>${c.description ?? ''}</p></section>` +
    `<section data-block="actions"><p>Call <code>erpax.chain.runFull({chainId: "${c.id}", tenantId: "...", locale: "en"})</code> via MCP.</p></section>`
}

function renderAgentPage(a: { id: string; ownsCollections: ReadonlyArray<string>; subscribesTo: ReadonlyArray<string>; emits: ReadonlyArray<string>; cron?: string }): string {
  return `<section data-block="hero"><h1>Agent: ${a.id}</h1></section>` +
    `<section data-block="surface"><h2>Surface</h2><ul>` +
    `<li><strong>Owns:</strong> ${a.ownsCollections.join(', ') || '(none)'}</li>` +
    `<li><strong>Subscribes:</strong> ${a.subscribesTo.join(', ') || '(none)'}</li>` +
    `<li><strong>Emits:</strong> ${a.emits.join(', ') || '(none)'}</li>` +
    `<li><strong>Cron:</strong> ${a.cron ?? '(event-driven only)'}</li></ul></section>`
}

function renderRolePage(r: { id: string; displayName: { [k: string]: string }; requiredStandards: ReadonlyArray<{ body: string; id: string }>; invariant: string }): string {
  const stds = r.requiredStandards.slice(0, 20).map((s) => `<li>${s.body} ${s.id}</li>`).join('')
  return `<section data-block="hero"><h1>${r.displayName.en ?? r.id}</h1><code>roleId: '${r.id}'</code></section>` +
    `<section data-block="standards"><h2>Required standards</h2><ul>${stds}</ul></section>` +
    `<section data-block="invariant"><h2>Conservation invariant</h2><code>${r.invariant}</code></section>`
}

function renderStandardFamilyPage(family: string): string {
  return `<section data-block="hero"><h1>${family}</h1></section>` +
    `<section data-block="description"><p>One of 7 standards-as-vortices families. See spec §0g.</p></section>` +
    `<section data-block="mcp-actions"><p>Browse the citation graph: <code>erpax.standards.classify({body: "..."})</code></p></section>`
}

/**
 * Export every PageSeed as a single .ndjson bundle for federation
 * broadcast (slice AAAAAA + EEEEEE pinning compatible).
 */
export function exportMediaBundle(seeds: ReadonlyArray<PageSeed>): string {
  return seeds.map((s) => JSON.stringify(s)).join('\n')
}

/** Parse a .ndjson bundle from another instance into PageSeed[]. */
export function importMediaBundle(ndjson: string): ReadonlyArray<PageSeed> {
  return ndjson.trim().split('\n').filter((l) => l).map((l) => JSON.parse(l) as PageSeed)
}

